const sheet = $('Get Rows').first().json;
let scrapedDesc = '';
let scrapedImage = '';

try {
  const scraped = $('Scrape Product').first().json;
  const meta = scraped.metadata || {};

  // Description fallback chain
  scrapedDesc = meta['og:description'] 
    || meta['twitter:description'] 
    || meta['description'] 
    || '';

  // Image fallback chain — try every possible metadata field
  const imageCandidate = meta['og:image:secure_url']
    || meta['og:image']
    || meta['og:image:url']
    || meta['twitter:image']
    || meta['twitter:image:src']
    || meta['image']
    || meta['thumbnail']
    || meta['sailthru.image.full']
    || meta['msapplication-TileImage']
    || '';

  // If metadata failed, try to find image URLs in the raw scraped content
  if (!imageCandidate && scraped.content) {
    const imgRegex = /https?:\/\/[^\s"'<>]+?\.(jpg|jpeg|png|webp|avif)(\?[^\s"'<>]*)?/gi;
    const matches = scraped.content.match(imgRegex);
    if (matches && matches.length > 0) {
      // Filter out tiny images (icons, tracking pixels) by looking for size hints
      const goodImages = matches.filter(url => {
        const lower = url.toLowerCase();
        return !lower.includes('favicon') 
          && !lower.includes('icon') 
          && !lower.includes('logo')
          && !lower.includes('pixel')
          && !lower.includes('badge')
          && !lower.includes('1x1');
      });
      scrapedImage = goodImages[0] || matches[0] || '';
    }
  } else {
    scrapedImage = imageCandidate;
  }

  // Fix protocol-relative URLs (starting with //)
  if (scrapedImage && scrapedImage.startsWith('//')) {
    scrapedImage = 'https:' + scrapedImage;
  }

  // Fix relative URLs (starting with /)
  if (scrapedImage && scrapedImage.startsWith('/') && !scrapedImage.startsWith('//')) {
    const productURL = sheet['Product URL']?.trim() || '';
    try {
      const base = new URL(productURL);
      scrapedImage = base.origin + scrapedImage;
    } catch (e) {}
  }

  // Strip whitespace and quotes that sometimes wrap URLs
  scrapedImage = scrapedImage.replace(/^["'\s]+|["'\s]+$/g, '');

} catch (e) {}

const description = sheet['Product Description']?.trim() || scrapedDesc;
const imagesRaw = sheet['Product Image(s) URL']?.trim() || scrapedImage;

const images = imagesRaw
  .split(/,(?=https?:\/\/)/)
  .map(url => url.trim())
  .filter(Boolean);

return [{
  json: {
    rowNumber: sheet['row_number'],
    brandLogo: sheet['Brand Logo URL']?.trim() || '',
    productURL: sheet['Product URL']?.trim() || '',
    productDescription: description,
    productImages: images,
    specification: sheet['Specification']?.trim() || '',
    postDate: sheet['Post Date']?.trim() || '',
    postHour: sheet['Post Hour']?.trim() || '',
    socials: sheet['Socials'].split(',').map(s => s.trim().toLowerCase()),
  }
}];

const parsed = $input.first().json.output;

return [{
  json: {
    caption: parsed.caption,
    hashtags: parsed.hashtags,
    slides: parsed.slides,
    productImages: $('Merge Data').first().json.productImages,
    brandLogo: $('Merge Data').first().json.brandLogo,
    rowNumber: $('Merge Data').first().json.rowNumber,
    socials: $('Merge Data').first().json.socials,
  }
}];

const data = $input.first().json;

async function toBase64(url) {
  if (!url) return null;
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    encoding: 'arraybuffer',
    returnFullResponse: true,
  });
  return Buffer.from(response.body).toString('base64');
}

const productImagesBase64 = await Promise.all(
  data.productImages.map(url => toBase64(url))
);

const brandLogoBase64 = await toBase64(data.brandLogo);

return [{
  json: {
    ...data,
    productImagesBase64,
    brandLogoBase64,
  }
}];

const data = $input.first().json;
const items = [];

const imageCount = data.productImagesBase64.filter(Boolean).length;

for (const slide of data.slides) {
  const parts = [];

  // Build prompt with image awareness
  let prompt = slide.imagePrompt;

  if (imageCount > 1) {
    prompt += `\n\nPRODUCT IMAGES: You are provided ${imageCount} different product images (different sizes/angles of the same product). Use ALL of them in the composition — feature the main one as the hero and use the others as supporting elements at different scales or angles to create depth and variety. Do not ignore any provided product image.`;
  }

  parts.push({ text: prompt });

  // Add product images with labels
  for (let i = 0; i < data.productImagesBase64.length; i++) {
    if (data.productImagesBase64[i]) {
      parts.push({
        inline_data: {
          mime_type: 'image/jpeg',
          data: data.productImagesBase64[i]
        }
      });
    }
  }

  // Add brand logo
  if (data.brandLogoBase64) {
    parts.push({
      inline_data: {
        mime_type: 'image/png',
        data: data.brandLogoBase64
      }
    });
  }

  items.push({
    json: {
      meta: {
        slideNumber: slide.slideNumber,
        headline: slide.headline,
        body: slide.body,
        caption: data.caption,
        hashtags: data.hashtags,
        rowNumber: data.rowNumber,
        socials: data.socials,
      },
      parts,
      generationConfig: {
        responseModalities: ["TEXT", "IMAGE"],
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "2K"
        }
      }
    }
  });
}

return items;

const item = $input.first().json;
const slideNumber = item.meta.slideNumber;
const staticData = $getWorkflowStaticData('global');

if (slideNumber === 1) {
  staticData.slideUrls = [];
}

const urls = staticData.slideUrls || [];
const basePrompt = item.parts[0].text;

let finalPrompt;

const renderingBlock = [
  'RENDERING INSTRUCTIONS:',
  '- The provided product photograph must be used as the MAIN SUBJECT.',
  '- The product must fill at least 50% of the frame — LARGE and dominant.',
  '- The provided brand logo must appear in the top-right or top-left corner at a tasteful size.',
  '- The product must be the BRIGHTEST and SHARPEST element in the entire frame.',
  '- Product shadow must be SOFT and SUBTLE — gentle contact shadow only. No heavy dark cast shadows.',
  '- Background must have DEPTH and TEXTURE — never plain flat beige, linen, or cream.',
  '- Typography must be LARGE and BOLD — headlines should fill at least 30% of the frame width.',
  '- All text described in the prompt must be rendered ON the image with the exact words specified.',
  '- Output must be exactly 1:1 square format (1024x1024).',
  '- Quality standard: this must look like a paid campaign from a luxury brand.',
  '- AVOID: organic wave shapes, scattered leaves, botanical decorations, heavy dark shadows, plain linen or beige textures, small product placement, soft pastel washes, Canva-style templates, decorative borders, blob shapes, flat backgrounds, competing fonts, purely decorative elements'
].join('\n');

const consistencyBlock = [
  'CRITICAL - VISUAL CONSISTENCY:',
  '- The PREVIOUS SLIDES from this carousel are attached as reference images.',
  '- You MUST match their exact color palette, typography style, font weight, lighting direction, lighting color temperature, background texture family, and signature design element.',
  '- The ONLY things that should change are: product position, product scale, text placement, composition layout, and background tone variation.',
  '- If the previous slides have a specific text rendering style, you MUST replicate that exact same style.',
  '- This slide must look like it belongs to the SAME campaign.'
].join('\n');

if (slideNumber === 1) {
  finalPrompt = basePrompt + '\n\n' + renderingBlock;
} else {
  finalPrompt = basePrompt + '\n\n' + renderingBlock + '\n\n' + consistencyBlock;
}

const parts = [{ text: finalPrompt }];

for (let i = 1; i < item.parts.length; i++) {
  parts.push(item.parts[i]);
}

for (const url of urls) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    encoding: 'arraybuffer',
    returnFullResponse: true,
  });
  const base64 = Buffer.from(response.body).toString('base64');
  parts.push({
    inline_data: {
      mime_type: 'image/jpeg',
      data: base64
    }
  });
}

return [{
  json: {
    meta: item.meta,
    contents: [{ parts: parts }],
    generationConfig: item.generationConfig,
    _debug: {
      slideNumber: slideNumber,
      previousUrlsCount: urls.length,
      previousUrls: urls.slice(),
      totalParts: parts.length
    }
  }
}];

const staticData = $getWorkflowStaticData('global');

if (!staticData.slideUrls) {
  staticData.slideUrls = [];
}

const mediaUrl = $('Blotato Upload').first().json.url;
staticData.slideUrls.push(mediaUrl);

return [{
  json: {
    meta: $('Add Previous Slides').first().json.meta,
    mediaUrl: mediaUrl,
    // DEBUG — remove after confirming
    _debug: {
      savedUrl: mediaUrl,
      totalStoredUrls: staticData.slideUrls.length,
      allStoredUrls: [...staticData.slideUrls],
    }
  }
}];

const items = $input.all();
const sheet = $('Get Rows').first().json;

const sorted = items.sort((a, b) =>
  a.json.meta.slideNumber - b.json.meta.slideNumber
);

const mediaUrls = sorted.map(item => item.json.mediaUrl);
const first = sorted[0].json.meta;

const postHour = sheet['Post Hour']?.toString().trim().toLowerCase();
let scheduledTime = '';

if (postHour && postHour !== 'now') {
  const today = new Date().toISOString().split('T')[0];
  let hours = 0;
  let minutes = 0;

  if (postHour.includes('am') || postHour.includes('pm')) {
    const isPM = postHour.includes('pm');
    const cleaned = postHour.replace(/[ap]m/gi, '').trim();
    const timeParts = cleaned.split(':');
    hours = parseInt(timeParts[0]);
    minutes = timeParts[1] ? parseInt(timeParts[1]) : 0;
    if (isPM && hours !== 12) hours += 12;
    if (!isPM && hours === 12) hours = 0;
  } else if (postHour.includes(':')) {
    const timeParts = postHour.split(':');
    hours = parseInt(timeParts[0]);
    minutes = parseInt(timeParts[1]);
  } else {
    hours = parseInt(postHour);
  }

  const hh = String(hours).padStart(2, '0');
  const mm = String(minutes).padStart(2, '0');
  scheduledTime = `${today}T${hh}:${mm}:00`;
}

return [{
  json: {
    mediaUrls: mediaUrls.join(','),
    caption: `${first.caption} ${first.hashtags}`,
    scheduledTime,
    rowNumber: first.rowNumber,
    socials: first.socials,
  }
}];

